diff --git a/llvm/lib/Transforms/IPO/SCCP.cpp b/llvm/lib/Transforms/IPO/SCCP.cpp
index d50de34dfa48..9af21cceac42 100644
--- a/llvm/lib/Transforms/IPO/SCCP.cpp
