@@ -28,6 +28,10 @@
 #include "llvm/Support/ModRef.h"
 #include "llvm/Transforms/IPO.h"
 #include "llvm/Transforms/IPO/FunctionSpecialization.h"
+#include "llvm/IR/CFG.h"
+#include "llvm/ADT/SmallVector.h"
+#include "llvm/ADT/SmallPtrSet.h"
+#include "llvm/ADT/PostOrderIterator.h"
 #include "llvm/Transforms/Scalar/SCCP.h"
 #include "llvm/Transforms/Utils/Local.h"
 #include "llvm/Transforms/Utils/SCCPSolver.h"
@@ -246,8 +250,25 @@ static bool runIPSCCP(
     for (BasicBlock &BB : F)
       MadeChanges |= Solver.removeNonFeasibleEdges(&BB, DTU, NewUnreachableBB);

+    // Remove incoming edges from dead predecessors to dead blocks to ensure
+    // that dead blocks have no predecessors when deleted.
+    SmallPtrSet<BasicBlock *, 32> DeadBlockSet(BlocksToErase.begin(),
+                                               BlocksToErase.end());
+    for (BasicBlock *DeadBB : BlocksToErase) {
+      // Make a copy of the predecessor list because it will be modified.
+      SmallVector<BasicBlock *, 8> Preds(pred_begin(DeadBB), pred_end(DeadBB));
+      for (BasicBlock *Pred : Preds) {
+        if (DeadBlockSet.contains(Pred)) {
+          // Both blocks are dead; remove the edge.
+          DeadBB->removePredecessor(Pred);
+          // No need to update the predecessor's terminator because it will be
+          // deleted later.
+        }
+      }
+    }
+
     for (BasicBlock *DeadBB : BlocksToErase)
-      if (!DeadBB->hasAddressTaken())
+      if (!DeadBB->hasAddressTaken() && DeadBB->pred_empty())
         DTU.deleteBB(DeadBB);

     Solver.removeSSACopies(F);
